import{c as a,Q as t,j as r,m as i}from"./chunks/framework.BkjtU8k0.js";const b=JSON.parse('{"title":"Vue2 历史版本","description":"","frontmatter":{},"headers":[],"relativePath":"guide/quickstart-vue2.md","filePath":"guide/quickstart-vue2.md","lastUpdated":1777273172000}'),l={name:"guide/quickstart-vue2.md"};function u(o,e,s,d,n,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="vue2-历史版本" tabindex="-1">Vue2 历史版本 <a class="header-anchor" href="#vue2-历史版本" aria-label="Permalink to &quot;Vue2 历史版本&quot;">​</a></h1><p>当前仓库维护主线是 <code>v3</code> 分支，对应 Vue 3 + Vite 版本。</p><p>如果你的业务系统仍然在 Vue2 上，建议优先使用 iframe 集成方式，让预览器作为独立页面接入，这样业务侧几乎不用承担解析依赖带来的升级压力。</p><h2 id="为什么推荐这样做" tabindex="-1">为什么推荐这样做 <a class="header-anchor" href="#为什么推荐这样做" aria-label="Permalink to &quot;为什么推荐这样做&quot;">​</a></h2><ul><li>Vue2 项目可以先稳定接入，不必等待整体迁移</li><li>预览器可以独立部署和升级，多系统复用时更省心</li><li>鉴权下载逻辑可以继续留在宿主系统中完成</li></ul><h2 id="vue2-相关历史资料" tabindex="-1">Vue2 相关历史资料 <a class="header-anchor" href="#vue2-相关历史资料" aria-label="Permalink to &quot;Vue2 相关历史资料&quot;">​</a></h2><ul><li>Vue2 说明文章: <a href="https://blog.csdn.net/wybaby168/article/details/129264431" target="_blank" rel="noreferrer">https://blog.csdn.net/wybaby168/article/details/129264431</a></li><li>项目背景文章: <a href="https://blog.csdn.net/wybaby168/article/details/122842866" target="_blank" rel="noreferrer">https://blog.csdn.net/wybaby168/article/details/122842866</a></li></ul><h2 id="推荐迁移路径" tabindex="-1">推荐迁移路径 <a class="header-anchor" href="#推荐迁移路径" aria-label="Permalink to &quot;推荐迁移路径&quot;">​</a></h2><ol><li>当前在 Vue2 项目中，通过 <a href="/guide/iframe">Iframe 嵌入</a> 先完成预览接入</li><li>业务未来升级到 Vue3 后，再根据需要切换到 <a href="/guide/quickstart-vue3">Vue3 集成</a></li></ol><div class="doc-note"> 这样做的好处很朴素: 你不用被某次框架升级卡住，预览能力也能继续平稳迭代。 </div>',10)])])}const _=a(l,[["render",u]]);export{b as __pageData,_ as default};
